code = """import json

# Re-run logic to check for ties
data = locals()['var_function-call-4346723004557668273']
if isinstance(data, str) and data.endswith('.json'):
    with open(data, 'r') as f:
        businesses = json.load(f)
else:
    businesses = data

category_counts = {}

def extract_categories(description):
    import re
    patterns = [
        r"services in (.*?)(?:\.|$)",
        r"including (.*?)(?:\.|$)",
        r"destination for (.*?)(?:\.|$)",
        r"fields of (.*?)(?:\.|$)"
    ]
    categories_str = None
    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            categories_str = match.group(1)
            break
    
    if not categories_str:
        return []

    parts = categories_str.split(',')
    cats = []
    for part in parts:
        part = part.strip()
        if part.lower().startswith('and '):
            part = part[4:].strip()
        if part:
            cats.append(part)
    return cats

for b in businesses:
    desc = b.get('description', '')
    cats = extract_categories(desc)
    for cat in cats:
        cat_clean = cat.strip()
        if cat_clean:
            category_counts[cat_clean] = category_counts.get(cat_clean, 0) + 1

if category_counts:
    max_count = max(category_counts.values())
    top_categories = [k for k, v in category_counts.items() if v == max_count]
else:
    top_categories = []

print("__RESULT__:")
print(json.dumps({"max_count": max_count, "top_categories": top_categories}))"""

